        String templateContent = "<div class='profile'>" +
                "<h2>用户资料</h2>" +
                "<p>用户名: ${username}</p>" +
                "<#if username?length gt 1>" +
                "<p>用户名长度: ${username?length}</p>" +
                "</#if>" +
                "<p>大写用户名: ${username?upper_case}</p>" +
                "</div>";
